import React, { useState, useEffect, useContext } from 'react';
import { Link } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import MovieCard from '../components/movies/MovieCard';
import LoadingSpinner from '../components/common/LoadingSpinner';
import {
  getMyRecommendations,
  getPopularMovies,
  getRecommendationsByGenre,
  getNewReleases
} from '../services/recommendationService';
import { getGenres } from '../services/movieService';
import '../styles/RecommendationsPage.css';

const RecommendationsPage = () => {
  const { user, isAuthenticated } = useContext(AuthContext);
  const [personalRecs, setPersonalRecs] = useState([]);
  const [popularMovies, setPopularMovies] = useState([]);
  const [genreRecs, setGenreRecs] = useState([]);
  const [newReleases, setNewReleases] = useState([]);
  const [genres, setGenres] = useState([]);
  const [selectedGenre, setSelectedGenre] = useState('');
  const [recType, setRecType] = useState('hybrid');
  const [loading, setLoading] = useState({
    personal: true,
    popular: true,
    genre: false,
    releases: true
  });
  const [errors, setErrors] = useState({});

  useEffect(() => {
    fetchInitialData();
  }, [isAuthenticated]);

  useEffect(() => {
    if (isAuthenticated) {
      fetchPersonalRecommendations();
    }
  }, [recType, isAuthenticated]);

  useEffect(() => {
    if (selectedGenre) {
      fetchGenreRecommendations();
    }
  }, [selectedGenre]);

  const fetchInitialData = async () => {
    try {
      // Fetch genres and popular movies for all users
      const [genresData, popularData, releasesData] = await Promise.all([
        getGenres(),
        getPopularMovies({ limit: 12 }),
        getNewReleases({ limit: 8 })
      ]);

      setGenres(genresData.genres);
      setPopularMovies(popularData.movies);
      setNewReleases(releasesData.movies);

      setLoading(prev => ({
        ...prev,
        popular: false,
        releases: false
      }));
    } catch (error) {
      console.error('Error fetching initial data:', error);
      setErrors(prev => ({
        ...prev,
        popular: 'Failed to load popular movies'
      }));
    }
  };

  const fetchPersonalRecommendations = async () => {
    if (!isAuthenticated) return;

    setLoading(prev => ({ ...prev, personal: true }));
    setErrors(prev => ({ ...prev, personal: null }));

    try {
      const data = await getMyRecommendations({
        type: recType,
        limit: 15
      });
      setPersonalRecs(data.recommendations);
    } catch (error) {
      console.error('Error fetching personal recommendations:', error);
      setErrors(prev => ({
        ...prev,
        personal: 'Failed to load personalized recommendations'
      }));
    } finally {
      setLoading(prev => ({ ...prev, personal: false }));
    }
  };

  const fetchGenreRecommendations = async () => {
    setLoading(prev => ({ ...prev, genre: true }));
    setErrors(prev => ({ ...prev, genre: null }));

    try {
      const data = await getRecommendationsByGenre(selectedGenre, { limit: 8 });
      setGenreRecs(data.movies);
    } catch (error) {
      console.error('Error fetching genre recommendations:', error);
      setErrors(prev => ({
        ...prev,
        genre: 'Failed to load genre recommendations'
      }));
    } finally {
      setLoading(prev => ({ ...prev, genre: false }));
    }
  };

  const handleGenreChange = (genre) => {
    setSelectedGenre(genre);
  };

  const handleRecTypeChange = (type) => {
    setRecType(type);
  };

  const renderSection = (title, movies, loading, error, emptyMessage) => (
    <section className="recommendation-section">
      <h2>{title}</h2>
      {loading ? (
        <div className="section-loading">
          <LoadingSpinner />
        </div>
      ) : error ? (
        <div className="error-message">
          <p>{error}</p>
          <button onClick={() => window.location.reload()}>Try Again</button>
        </div>
      ) : movies.length > 0 ? (
        <div className="movies-grid">
          {movies.map(movie => (
            <MovieCard key={movie.id} movie={movie} showRecommendationScore={true} />
          ))}
        </div>
      ) : (
        <div className="empty-section">
          <p>{emptyMessage}</p>
        </div>
      )}
    </section>
  );

  if (!isAuthenticated) {
    return (
      <div className="recommendations-page">
        <div className="auth-required">
          <h1>🎯 Personalized Recommendations</h1>
          <div className="auth-message">
            <h3>Sign in to get personalized movie recommendations</h3>
            <p>
              Create an account or sign in to receive recommendations based on your taste
              and what similar users are watching.
            </p>
            <div className="auth-buttons">
              <Link to="/login" className="auth-button primary">
                Sign In
              </Link>
              <Link to="/register" className="auth-button secondary">
                Create Account
              </Link>
            </div>
          </div>

          {/* Show popular movies for non-authenticated users */}
          {renderSection(
            '🔥 Popular Movies',
            popularMovies,
            loading.popular,
            errors.popular,
            'No popular movies available'
          )}

          {renderSection(
            '🆕 New Releases',
            newReleases,
            loading.releases,
            errors.releases,
            'No new releases available'
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="recommendations-page">
      <div className="page-header">
        <h1>🎯 Your Recommendations</h1>
        <p>Personalized movie suggestions just for you, {user?.username}!</p>
      </div>

      {/* Personal Recommendations Section */}
      <section className="recommendation-section featured">
        <div className="section-header">
          <h2>🎬 For You</h2>
          <div className="recommendation-controls">
            <label>Algorithm:</label>
            <select
              value={recType}
              onChange={(e) => handleRecTypeChange(e.target.value)}
              className="rec-type-select"
            >
              <option value="hybrid">Smart Mix (Hybrid)</option>
              <option value="collaborative">Similar Users</option>
              <option value="content">Your Preferences</option>
            </select>
          </div>
        </div>

        <div className="algorithm-info">
          {recType === 'hybrid' && (
            <p>🧠 Using a combination of your preferences and similar users' choices</p>
          )}
          {recType === 'collaborative' && (
            <p>👥 Based on users with similar taste to yours</p>
          )}
          {recType === 'content' && (
            <p>🎭 Based on genres and movies you've enjoyed</p>
          )}
        </div>

        {loading.personal ? (
          <div className="section-loading">
            <LoadingSpinner />
            <p>Analyzing your preferences...</p>
          </div>
        ) : errors.personal ? (
          <div className="error-message">
            <p>{errors.personal}</p>
            <button onClick={fetchPersonalRecommendations}>Try Again</button>
          </div>
        ) : personalRecs.length > 0 ? (
          <div className="movies-grid">
            {personalRecs.map(movie => (
              <MovieCard 
                key={movie.id} 
                movie={movie} 
                showRecommendationScore={true}
                recommendationSources={movie.recommendation_sources}
              />
            ))}
          </div>
        ) : (
          <div className="empty-recommendations">
            <h3>No recommendations yet</h3>
            <p>Rate some movies to get personalized recommendations!</p>
            <Link to="/movies" className="rate-movies-button">
              Browse & Rate Movies
            </Link>
          </div>
        )}
      </section>

      {/* Genre-Based Recommendations */}
      <section className="recommendation-section">
        <div className="section-header">
          <h2>🎭 By Genre</h2>
          <div className="genre-selector">
            <select
              value={selectedGenre}
              onChange={(e) => handleGenreChange(e.target.value)}
              className="genre-select"
            >
              <option value="">Choose a genre...</option>
              {genres.map(genre => (
                <option key={genre.name} value={genre.name}>
                  {genre.name}
                </option>
              ))}
            </select>
          </div>
        </div>

        {selectedGenre && (
          <>
            {loading.genre ? (
              <div className="section-loading">
                <LoadingSpinner />
              </div>
            ) : errors.genre ? (
              <div className="error-message">
                <p>{errors.genre}</p>
                <button onClick={fetchGenreRecommendations}>Try Again</button>
              </div>
            ) : genreRecs.length > 0 ? (
              <div className="movies-grid">
                {genreRecs.map(movie => (
                  <MovieCard key={movie.id} movie={movie} />
                ))}
              </div>
            ) : (
              <div className="empty-section">
                <p>No {selectedGenre} recommendations found</p>
              </div>
            )}
          </>
        )}
      </section>

      {/* Popular Movies Section */}
      {renderSection(
        '🔥 Trending Now',
        popularMovies,
        loading.popular,
        errors.popular,
        'No popular movies available'
      )}

      {/* New Releases Section */}
      {renderSection(
        '🆕 New Releases',
        newReleases,
        loading.releases,
        errors.releases,
        'No new releases available'
      )}

      {/* Recommendation Tips */}
      <section className="recommendation-tips">
        <h3>💡 Get Better Recommendations</h3>
        <div className="tips-grid">
          <div className="tip-card">
            <h4>Rate More Movies</h4>
            <p>The more movies you rate, the better our recommendations become</p>
            <Link to="/movies">Browse Movies →</Link>
          </div>
          <div className="tip-card">
            <h4>Try Different Genres</h4>
            <p>Rate movies from various genres to discover new favorites</p>
          </div>
          <div className="tip-card">
            <h4>Write Reviews</h4>
            <p>Add reviews to your ratings to help the algorithm understand your taste</p>
            <Link to="/my-ratings">View Your Ratings →</Link>
          </div>
        </div>
      </section>
    </div>
  );
};

export default RecommendationsPage;
